// ── MAIN ─────────────────────────────────────────────────────────────────────

async function seed() {
  if (!process.env.SANITY_API_WRITE_TOKEN) {
    console.error("❌  SANITY_API_WRITE_TOKEN is required.");
    process.exit(1);
  }

  console.log("🌱  Seeding dataset:", process.env.NEXT_PUBLIC_SANITY_DATASET ?? "production");

  console.log("\n📂  Upserting categories...");
  for (const cat of categories) {
    await client.createOrReplace(cat);
    console.log("   ✓", cat.label);
  }

  console.log("\n📋  Upserting checklists...");
  for (const cl of allChecklists) {
    await client.createOrReplace(cl);
    console.log("   ✓", cl.title);
  }

  console.log("\n📰  Upserting blog posts...");
  for (const post of blogPosts) {
    await client.createOrReplace(post);
    console.log("   ✓", post.title);
  }

  console.log("\n✅  Set 1 done (20 checklists). Run seed again after adding Sets 2 & 3.");
}

seed().catch((err) => {
  console.error("❌  Seed failed:", err.message);
  process.exit(1);
});
